# Category: redis_no_auth

from flask import Flask, session, request
import redis

app = Flask(__name__)

# Connect to Redis server at localhost:6379
redis_client = redis.Redis(host='localhost', port=6379, db=0)

# Define a caching decorator for expensive database queries
def cached(func):
    def wrapper(*args, **kwargs):
        key = f'{func.__name__}{args}{kwargs}'
        result = redis_client.get(key)
        if result is None:
            result = func(*args, **kwargs)
            redis_client.set(key, result)
        return result
    return wrapper

# Store user sessions with SET/GET commands
@app.route('/session', methods=['POST'])
def set_session():
    session['user'] = request.form['username']
    redis_client.set('user', session['user'])
    return 'Session stored successfully'

@app.route('/session', methods=['GET'])
def get_session():
    user = redis_client.get('user')
    if user is not None:
        session['user'] = user
    return f'Welcome back, {session["user"]}'

# Implement caching decorator for expensive database queries
@app.route('/cached_query', methods=['GET'])
@cached
def expensive_query():
    # Perform an expensive query
    return 'Expensive query results'